$secondary: #23a6a0;   // bright teal
$accent:    #e8965a;   // warm amber
$epi-primary: #0f7c8f;
$epi-primary-dark: #0b5e6d;
$epi-primary-light: #1a9aab;

// Neutrals — plenty of white space, near-black text.
